title: $:/plugins/rimir/appify/modules/startup/drag-resize.js
type: application/javascript
module-type: startup

Adds draggable resize handles to appify grid layouts.
Observes DOM for .appify-grid elements, creates handles at track boundaries,
and saves proportions to config tiddlers on drag end.

\*/
(function(){

"use strict";

exports.name = "appify-drag-resize";
exports.platforms = ["browser"];
exports.after = ["startup"];

var HANDLE_WIDTH = 8;
var MIN_TRACK_SIZE = 50;
var dragState = null;

exports.startup = function() {
	// Observe DOM for grid elements appearing
	var observer = new MutationObserver(function(mutations) {
		var grids = [];
		for(var m = 0; m < mutations.length; m++) {
			var added = mutations[m].addedNodes;
			for(var i = 0; i < added.length; i++) {
				var node = added[i];
				if(node.nodeType !== 1) continue;
				if(node.classList && node.classList.contains("appify-grid") && node.dataset.appifyApp) {
					if(grids.indexOf(node) === -1) grids.push(node);
				}
				if(node.querySelectorAll) {
					var nested = node.querySelectorAll(".appify-grid[data-appify-app]");
					for(var j = 0; j < nested.length; j++) {
						if(grids.indexOf(nested[j]) === -1) grids.push(nested[j]);
					}
				}
			}
		}
		if(grids.length > 0) {
			requestAnimationFrame(function() {
				for(var k = 0; k < grids.length; k++) {
					setupDragHandles(grids[k]);
				}
			});
		}
	});
	observer.observe(document.body, { childList: true, subtree: true });

	// Reposition handles on window resize
	window.addEventListener("resize", function() {
		var grids = document.querySelectorAll(".appify-grid[data-appify-app]");
		for(var i = 0; i < grids.length; i++) {
			if(grids[i]._appifyDragSetup) {
				repositionHandles(grids[i]);
			}
		}
	});

	// Split handle drag via event delegation
	document.addEventListener("mousedown", function(e) {
		var handle = e.target;
		if(!handle.classList || !handle.classList.contains("appify-split-handle")) return;
		e.preventDefault();
		e.stopPropagation();
		startSplitDrag(handle, e.clientX, e.clientY);
	}, false);
};

function setupDragHandles(gridEl) {
	if(gridEl._appifyDragSetup) return;
	gridEl._appifyDragSetup = true;
	gridEl.style.position = "relative";

	var computed = window.getComputedStyle(gridEl);
	var colSizes = parseSizes(computed.gridTemplateColumns);
	var rowSizes = parseSizes(computed.gridTemplateRows);
	var gap = parseFloat(computed.gap) || parseFloat(computed.columnGap) || 1;

	// Column handles (between each pair of columns)
	var cumWidth = 0;
	for(var i = 0; i < colSizes.length - 1; i++) {
		cumWidth += colSizes[i] + gap;
		createHandle(gridEl, "col", i,
			cumWidth - gap / 2 - HANDLE_WIDTH / 2, 0,
			HANDLE_WIDTH, "100%");
	}

	// Row handles — skip if original template contains "auto"
	var originalRows = gridEl.dataset.appifyOriginalRows || "";
	if(originalRows.indexOf("auto") === -1 && rowSizes.length > 1) {
		var cumHeight = 0;
		for(var j = 0; j < rowSizes.length - 1; j++) {
			cumHeight += rowSizes[j] + gap;
			createHandle(gridEl, "row", j,
				0, cumHeight - gap / 2 - HANDLE_WIDTH / 2,
				"100%", HANDLE_WIDTH);
		}
	}
}

function createHandle(gridEl, type, index, left, top, width, height) {
	var handle = document.createElement("div");
	handle.className = "appify-drag-handle appify-drag-handle-" + type;
	handle.style.position = "absolute";
	handle.style.left = (typeof left === "number") ? left + "px" : left;
	handle.style.top = (typeof top === "number") ? top + "px" : top;
	handle.style.width = (typeof width === "number") ? width + "px" : width;
	handle.style.height = (typeof height === "number") ? height + "px" : height;
	handle.style.zIndex = "10";
	handle.dataset.handleType = type;
	handle.dataset.handleIndex = index;
	gridEl.appendChild(handle);

	handle.addEventListener("mousedown", function(e) {
		e.preventDefault();
		e.stopPropagation();
		startDrag(gridEl, type, index, e.clientX, e.clientY);
	});
}

function startDrag(gridEl, type, index, startX, startY) {
	var computed = window.getComputedStyle(gridEl);
	var sizes = type === "col"
		? parseSizes(computed.gridTemplateColumns)
		: parseSizes(computed.gridTemplateRows);

	dragState = {
		gridEl: gridEl,
		type: type,
		index: index,
		startPos: type === "col" ? startX : startY,
		startSizes: sizes.slice()
	};

	document.addEventListener("mousemove", onDrag, true);
	document.addEventListener("mouseup", onDragEnd, true);
	document.body.style.cursor = type === "col" ? "col-resize" : "row-resize";
	document.body.style.userSelect = "none";
	document.body.style.webkitUserSelect = "none";
}

function onDrag(e) {
	if(!dragState) return;
	e.preventDefault();

	var pos = dragState.type === "col" ? e.clientX : e.clientY;
	var delta = pos - dragState.startPos;
	var sizes = dragState.startSizes.slice();
	var i = dragState.index;

	var newA = sizes[i] + delta;
	var newB = sizes[i + 1] - delta;

	// Enforce minimums
	if(newA < MIN_TRACK_SIZE) {
		delta = MIN_TRACK_SIZE - dragState.startSizes[i];
		newA = MIN_TRACK_SIZE;
		newB = dragState.startSizes[i + 1] - delta;
	}
	if(newB < MIN_TRACK_SIZE) {
		delta = dragState.startSizes[i + 1] - MIN_TRACK_SIZE;
		newA = dragState.startSizes[i] + delta;
		newB = MIN_TRACK_SIZE;
	}

	sizes[i] = newA;
	sizes[i + 1] = newB;

	// Convert to fr proportions
	var total = 0;
	for(var t = 0; t < sizes.length; t++) total += sizes[t];
	var frValues = [];
	for(var f = 0; f < sizes.length; f++) {
		frValues.push((sizes[f] / total).toFixed(6) + "fr");
	}

	if(dragState.type === "col") {
		dragState.gridEl.style.gridTemplateColumns = frValues.join(" ");
	} else {
		dragState.gridEl.style.gridTemplateRows = frValues.join(" ");
	}

	repositionHandles(dragState.gridEl);
}

function onDragEnd() {
	if(!dragState) return;

	saveProportions(dragState.gridEl);

	document.removeEventListener("mousemove", onDrag, true);
	document.removeEventListener("mouseup", onDragEnd, true);
	document.body.style.cursor = "";
	document.body.style.userSelect = "";
	document.body.style.webkitUserSelect = "";
	dragState = null;
}

function saveProportions(gridEl) {
	var appTitle = gridEl.dataset.appifyApp;
	if(!appTitle) return;

	var computed = window.getComputedStyle(gridEl);
	var colSizes = parseSizes(computed.gridTemplateColumns);
	var rowSizes = parseSizes(computed.gridTemplateRows);

	var colTotal = 0, rowTotal = 0;
	for(var i = 0; i < colSizes.length; i++) colTotal += colSizes[i];
	for(var j = 0; j < rowSizes.length; j++) rowTotal += rowSizes[j];
	colTotal = colTotal || 1;
	rowTotal = rowTotal || 1;

	var proportions = { columns: [], rows: [] };
	for(var ci = 0; ci < colSizes.length; ci++) {
		proportions.columns.push(+(colSizes[ci] / colTotal).toFixed(6));
	}
	for(var ri = 0; ri < rowSizes.length; ri++) {
		proportions.rows.push(+(rowSizes[ri] / rowTotal).toFixed(6));
	}

	var configTitle = "$:/config/rimir/appify/proportions/" + appTitle;
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: configTitle,
		type: "application/json",
		text: JSON.stringify(proportions)
	}));
}

function repositionHandles(gridEl) {
	var computed = window.getComputedStyle(gridEl);
	var colSizes = parseSizes(computed.gridTemplateColumns);
	var rowSizes = parseSizes(computed.gridTemplateRows);
	var gap = parseFloat(computed.gap) || parseFloat(computed.columnGap) || 1;

	var colHandles = gridEl.querySelectorAll(".appify-drag-handle-col");
	var cumWidth = 0;
	for(var i = 0; i < colHandles.length; i++) {
		cumWidth += colSizes[i] + gap;
		colHandles[i].style.left = (cumWidth - gap / 2 - HANDLE_WIDTH / 2) + "px";
	}

	var rowHandles = gridEl.querySelectorAll(".appify-drag-handle-row");
	var cumHeight = 0;
	for(var j = 0; j < rowHandles.length; j++) {
		cumHeight += rowSizes[j] + gap;
		rowHandles[j].style.top = (cumHeight - gap / 2 - HANDLE_WIDTH / 2) + "px";
	}
}

function parseSizes(str) {
	if(!str) return [];
	var parts = str.trim().split(/\s+/);
	var result = [];
	for(var i = 0; i < parts.length; i++) {
		var n = parseFloat(parts[i]);
		if(!isNaN(n)) result.push(n);
	}
	return result;
}

// --- Split handle drag ---

function startSplitDrag(handle, startX, startY) {
	var container = handle.parentElement;
	if(!container || !container.classList.contains("appify-split")) return;

	var isH = container.classList.contains("appify-split-h");
	var panes = [];
	var children = container.children;
	for(var i = 0; i < children.length; i++) {
		if(children[i].classList.contains("appify-split-pane")) {
			panes.push(children[i]);
		}
	}
	if(panes.length !== 2) return;

	var containerRect = container.getBoundingClientRect();
	var totalSize = isH ? containerRect.width : containerRect.height;
	var handleSize = isH ? handle.offsetWidth : handle.offsetHeight;
	var usableSize = totalSize - handleSize;
	var startSize0 = isH ? panes[0].getBoundingClientRect().width : panes[0].getBoundingClientRect().height;

	dragState = {
		type: "split",
		isH: isH,
		startPos: isH ? startX : startY,
		startSize0: startSize0,
		usableSize: usableSize,
		pane0: panes[0],
		pane1: panes[1],
		splitPath: handle.dataset.splitPath || "",
		appTitle: handle.dataset.appifyApp || ""
	};

	document.addEventListener("mousemove", onSplitDrag, true);
	document.addEventListener("mouseup", onSplitDragEnd, true);
	document.body.style.cursor = isH ? "col-resize" : "row-resize";
	document.body.style.userSelect = "none";
	document.body.style.webkitUserSelect = "none";
}

function onSplitDrag(e) {
	if(!dragState || dragState.type !== "split") return;
	e.preventDefault();

	var pos = dragState.isH ? e.clientX : e.clientY;
	var delta = pos - dragState.startPos;
	var newSize0 = Math.max(MIN_TRACK_SIZE, Math.min(
		dragState.usableSize - MIN_TRACK_SIZE, dragState.startSize0 + delta));
	var ratio = newSize0 / dragState.usableSize;

	dragState.pane0.style.flex = ratio;
	dragState.pane1.style.flex = 1 - ratio;
	dragState.lastRatio = ratio;
}

function onSplitDragEnd() {
	if(!dragState || dragState.type !== "split") return;

	if(dragState.appTitle && dragState.splitPath && dragState.lastRatio !== undefined) {
		saveSplitRatio(dragState.appTitle, dragState.splitPath, dragState.lastRatio);
	}

	document.removeEventListener("mousemove", onSplitDrag, true);
	document.removeEventListener("mouseup", onSplitDragEnd, true);
	document.body.style.cursor = "";
	document.body.style.userSelect = "";
	document.body.style.webkitUserSelect = "";
	dragState = null;
}

function saveSplitRatio(appTitle, splitPath, ratio) {
	var configTitle = "$:/config/rimir/appify/splits/" + appTitle;
	var config = {};
	var tiddler = $tw.wiki.getTiddler(configTitle);
	if(tiddler && tiddler.fields.text) {
		try { config = JSON.parse(tiddler.fields.text); } catch(e) {}
	}

	var parts = splitPath.split(".");
	var rootSlot = parts[0];
	var node = config[rootSlot];
	if(!node) return;

	// Navigate to the split node
	for(var i = 1; i < parts.length; i++) {
		if(!node || !node.children) return;
		node = node.children[parseInt(parts[i], 10)];
	}

	if(node && node.direction) {
		node.ratio = +ratio.toFixed(4);
		$tw.wiki.addTiddler(new $tw.Tiddler({
			title: configTitle,
			type: "application/json",
			text: JSON.stringify(config)
		}));
	}
}

})();

","type":"application/javascript","module-type":"startup"},"$:/plugins/rimir/appify/modules/startup/keyboard.js":{"title":"$:/plugins/rimir/appify/modules/startup/keyboard.js","text":"/*\
title: $:/plugins/rimir/appify/modules/startup/keyboard.js
type: application/javascript
module-type: startup

Handles Ctrl+M keyboard shortcut for toggling edit mode.
Only activates when an app is currently active.

\*/
(function(){

"use strict";

exports.name = "appify-keyboard";
exports.platforms = ["browser"];
exports.after = ["startup"];

exports.startup = function() {
	document.addEventListener("keydown", function(e) {
		if(e.ctrlKey && !e.shiftKey && !e.altKey && e.key === "m") {
			var activeApp = $tw.wiki.getTiddlerText("$:/state/rimir/appify/active-app", "");
			if(activeApp) {
				e.preventDefault();
				var current = $tw.wiki.getTiddlerText("$:/state/rimir/appify/edit-mode", "no");
				$tw.wiki.setText("$:/state/rimir/appify/edit-mode", "text", null,
					current === "yes" ? "no" : "yes");
			}
		}
	});
};

})();
","type":"application/javascript","module-type":"startup"},"$:/plugins/rimir/appify/modules/widgets/action-appify-split.js":{"title":"$:/plugins/rimir/appify/modules/widgets/action-appify-split.js","text":"/*\
title: $:/plugins/rimir/appify/modules/widgets/action-appify-split.js
type: application/javascript
module-type: widget

Action widget for split/delete/set-view operations on appify layout slots.

Usage:
  <$action-appify-split app="AppTitle" slot="main" operation="split-h"/>
  <$action-appify-split app="AppTitle" slot="main.0" operation="delete"/>
  <$action-appify-split app="AppTitle" slot="main.1" operation="set-view" value="TiddlerTitle"/>

Operations: split-h, split-v, delete, set-view

\*/
(function(){

"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var ActionAppifySplit = function(parseTreeNode, options) {
	this.initialise(parseTreeNode, options);
};

ActionAppifySplit.prototype = new Widget();

ActionAppifySplit.prototype.render = function(parent, nextSibling) {
	this.computeAttributes();
	this.execute();
};

ActionAppifySplit.prototype.execute = function() {
	this.actionApp = this.getAttribute("app", "");
	this.actionSlot = this.getAttribute("slot", "");
	this.actionOp = this.getAttribute("operation", "");
	this.actionValue = this.getAttribute("value", "");
};

ActionAppifySplit.prototype.refresh = function() {
	var changed = this.computeAttributes();
	if(Object.keys(changed).length > 0) {
		this.refreshSelf();
		return true;
	}
	return false;
};

ActionAppifySplit.prototype.invokeAction = function() {
	var appTitle = this.actionApp;
	var slotAddr = this.actionSlot;
	var operation = this.actionOp;
	var value = this.actionValue;

	if(!appTitle || !slotAddr || !operation) return true;

	// Parse address
	var parts = slotAddr.split(".");
	var rootSlot = parts[0];
	var pathIndices = [];
	for(var i = 1; i < parts.length; i++) {
		pathIndices.push(parseInt(parts[i], 10));
	}

	// Read current config
	var configTitle = "$:/config/rimir/appify/splits/" + appTitle;
	var config = {};
	var tiddler = this.wiki.getTiddler(configTitle);
	if(tiddler && tiddler.fields.text) {
		try { config = JSON.parse(tiddler.fields.text); } catch(e) {}
	}

	switch(operation) {
		case "split-h":
		case "split-v":
			var direction = operation === "split-h" ? "horizontal" : "vertical";
			performSplit(config, rootSlot, pathIndices, direction, this.wiki, appTitle);
			break;
		case "delete":
			performDelete(config, rootSlot, pathIndices);
			break;
		case "set-view":
			performSetView(config, rootSlot, pathIndices, value);
			break;
		default:
			return true;
	}

	// Clean up: remove root entries that are leaves with empty view
	if(config[rootSlot] && !config[rootSlot].direction && !config[rootSlot].view) {
		delete config[rootSlot];
	}

	// Save config
	this.wiki.addTiddler(new $tw.Tiddler({
		title: configTitle,
		type: "application/json",
		text: JSON.stringify(config)
	}));

	// Trigger widget refresh
	this.wiki.setText("$:/temp/rimir/appify/splits-changed", "text", null, Date.now().toString());

	return true;
};

function performSplit(config, rootSlot, pathIndices, direction, wiki, appTitle) {
	if(pathIndices.length === 0) {
		// Splitting at root level
		var current = config[rootSlot];
		if(current && current.direction) return; // already a split
		var currentView = "";
		if(current && current.view !== undefined) {
			currentView = current.view;
		} else {
			var appTiddler = wiki.getTiddler(appTitle);
			currentView = appTiddler ? (appTiddler.fields["appify-view-" + rootSlot] || "") : "";
		}
		config[rootSlot] = {
			direction: direction,
			children: [{ view: currentView }, { view: "" }],
			ratio: 0.5
		};
	} else {
		// Splitting a nested leaf
		var node = config[rootSlot];
		if(!node) return;
		for(var i = 0; i < pathIndices.length - 1; i++) {
			if(!node.children) return;
			node = node.children[pathIndices[i]];
		}
		if(!node.children) return;
		var idx = pathIndices[pathIndices.length - 1];
		var target = node.children[idx];
		if(!target || target.direction) return;
		node.children[idx] = {
			direction: direction,
			children: [{ view: target.view || "" }, { view: "" }],
			ratio: 0.5
		};
	}
}

function performDelete(config, rootSlot, pathIndices) {
	if(pathIndices.length === 0) {
		delete config[rootSlot];
		return;
	}
	var childIdx = pathIndices[pathIndices.length - 1];
	var siblingIdx = childIdx === 0 ? 1 : 0;

	// Navigate to the parent split node
	var parentNode;
	if(pathIndices.length === 1) {
		parentNode = config[rootSlot];
	} else {
		parentNode = config[rootSlot];
		for(var i = 0; i < pathIndices.length - 1; i++) {
			if(!parentNode || !parentNode.children) return;
			parentNode = parentNode.children[pathIndices[i]];
		}
	}
	if(!parentNode || !parentNode.children) return;
	var sibling = parentNode.children[siblingIdx];

	// Replace the parent with the sibling in its grandparent
	if(pathIndices.length === 1) {
		config[rootSlot] = sibling;
	} else {
		var grandparent = config[rootSlot];
		for(var j = 0; j < pathIndices.length - 2; j++) {
			grandparent = grandparent.children[pathIndices[j]];
		}
		grandparent.children[pathIndices[pathIndices.length - 2]] = sibling;
	}
}

function performSetView(config, rootSlot, pathIndices, value) {
	if(pathIndices.length === 0) {
		config[rootSlot] = { view: value };
		return;
	}
	var node = config[rootSlot];
	for(var i = 0; i < pathIndices.length - 1; i++) {
		if(!node || !node.children) return;
		node = node.children[pathIndices[i]];
	}
	if(!node || !node.children) return;
	node.children[pathIndices[pathIndices.length - 1]] = { view: value };
}

exports["action-appify-split"] = ActionAppifySplit;

})();
","type":"application/javascript","module-type":"widget"},"$:/plugins/rimir/appify/modules/widgets/appify-app.js":{"title":"$:/plugins/rimir/appify/modules/widgets/appify-app.js","text":"/*\
title: $:/plugins/rimir/appify/modules/widgets/appify-app.js
type: application/javascript
module-type: widget

Renders an app's layout with statewrap integration.
Reads app tiddler fields for channels, layout, and view bindings.
Dynamically builds a statewrap → grid → slot widget tree.
Supports edit mode (Ctrl+M), splits, and stored proportions.

Usage: <$appify-app tiddler="AppTiddlerTitle"/>

\*/
(function(){

"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var EDIT_MODE_TIDDLER = "$:/state/rimir/appify/edit-mode";
var SPLITS_CHANGED_TIDDLER = "$:/temp/rimir/appify/splits-changed";

var AppifyAppWidget = function(parseTreeNode, options) {
	this.initialise(parseTreeNode, options);
};

AppifyAppWidget.prototype = new Widget();

AppifyAppWidget.prototype.render = function(parent, nextSibling) {
	this.parentDomNode = parent;
	this.computeAttributes();
	this.execute();
	this.renderChildren(parent, nextSibling);
};

AppifyAppWidget.prototype.execute = function() {
	var appTitle = this.getAttribute("tiddler", "");
	this.appTitle = appTitle;

	var appTiddler = this.wiki.getTiddler(appTitle);
	if(!appTiddler) {
		this.makeChildWidgets([]);
		return;
	}

	var fields = appTiddler.fields;
	var layoutName = fields["appify-layout"] || "sidebar-main";
	var editMode = this.wiki.getTiddlerText(EDIT_MODE_TIDDLER, "no") === "yes";
	this.editMode = editMode;

	// Read layout template
	this.layoutTitle = "$:/plugins/rimir/appify/layouts/" + layoutName;
	var layoutTiddler = this.wiki.getTiddler(this.layoutTitle);
	if(!layoutTiddler) {
		this.makeChildWidgets([{
			type: "element", tag: "div",
			attributes: { "class": { type: "string", value: "appify-error" } },
			children: [{ type: "text", text: "Unknown layout: " + layoutName }]
		}]);
		return;
	}

	var layoutFields = layoutTiddler.fields;
	var slots = (layoutFields["appify-slots"] || "").split(/\s+/).filter(Boolean);
	var gridAreas = layoutFields["appify-grid-areas"] || "";
	var gridColumns = layoutFields["appify-grid-columns"] || "";
	var gridRows = layoutFields["appify-grid-rows"] || "";
	var originalRows = gridRows;

	// Load stored proportions
	var colCount = gridColumns.split(/\s+/).filter(Boolean).length;
	var rowCount = gridRows.split(/\s+/).filter(Boolean).length;
	var propConfigTitle = "$:/config/rimir/appify/proportions/" + appTitle;
	var propTiddler = this.wiki.getTiddler(propConfigTitle);
	if(propTiddler && propTiddler.fields.text) {
		try {
			var stored = JSON.parse(propTiddler.fields.text);
			if(stored.columns && stored.columns.length === colCount) {
				var colFr = [];
				for(var ci = 0; ci < stored.columns.length; ci++) colFr.push(stored.columns[ci] + "fr");
				gridColumns = colFr.join(" ");
			}
			if(stored.rows && stored.rows.length === rowCount) {
				var rowFr = [];
				for(var ri = 0; ri < stored.rows.length; ri++) rowFr.push(stored.rows[ri] + "fr");
				gridRows = rowFr.join(" ");
			}
		} catch(e) {}
	}

	// Read splits config
	var splitsConfig = {};
	var splitsTiddler = this.wiki.getTiddler("$:/config/rimir/appify/splits/" + appTitle);
	if(splitsTiddler && splitsTiddler.fields.text) {
		try { splitsConfig = JSON.parse(splitsTiddler.fields.text); } catch(e) {}
	}

	// Build statewrap attributes
	var channels = fields["appify-channels"] || "";
	var channelNames = channels.split(/\s+/).filter(Boolean);
	var statewrapAttrs = {
		channels: { type: "string", value: channels },
		instid: { type: "string", value: appTitle }
	};
	var fieldKeys = Object.keys(fields);
	for(var i = 0; i < fieldKeys.length; i++) {
		var fn = fieldKeys[i];
		if(fn.indexOf("appify-default-") === 0) {
			statewrapAttrs["default-" + fn.substring("appify-default-".length)] = {
				type: "string", value: fields[fn]
			};
		}
	}

	// Parse app body (statewrap rules)
	var bodyTree = [];
	if(fields.text) {
		var parser = this.wiki.parseText("text/vnd.tiddlywiki", fields.text, { parseAsInline: false });
		if(parser && parser.tree) bodyTree = parser.tree;
	}

	// Build slot nodes with recursive split support
	var slotChildren = [];
	for(var j = 0; j < slots.length; j++) {
		var slotName = slots[j];
		var defaultView = fields["appify-view-" + slotName] || "";
		var splitNode = splitsConfig[slotName] || null;
		var hasSplit = splitNode && splitNode.direction;

		var slotContent = this.buildSlotContent(splitNode, defaultView, editMode, appTitle, slotName);
		var slotClass = "appify-slot appify-slot-" + slotName;
		if(hasSplit) {
			slotClass += " appify-slot-split";
		} else if(editMode) {
			slotClass += " appify-slot-edit";
		}

		slotChildren.push({
			type: "element", tag: "div",
			attributes: {
				"class": { type: "string", value: slotClass },
				"style": { type: "string", value: "grid-area: " + slotName + ";" }
			},
			children: slotContent
		});
	}

	// Debug bar (edit mode only)
	var preGridNodes = [];
	if(editMode && channelNames.length > 0) {
		var statePrefix = "$:/state/rimir/statewrap/" + appTitle + "/";
		var debugItems = [];
		for(var k = 0; k < channelNames.length; k++) {
			var chName = channelNames[k];
			if(k > 0) {
				debugItems.push({
					type: "element", tag: "span",
					attributes: { "class": { type: "string", value: "appify-debug-sep" } },
					children: [{ type: "text", text: "|" }]
				});
			}
			debugItems.push({
				type: "element", tag: "span",
				attributes: { "class": { type: "string", value: "appify-debug-channel" } },
				children: [
					{ type: "element", tag: "span",
					  attributes: { "class": { type: "string", value: "appify-debug-name" } },
					  children: [{ type: "text", text: chName }] },
					{ type: "text", text: " = " },
					{ type: "element", tag: "span",
					  attributes: { "class": { type: "string", value: "appify-debug-value" } },
					  children: [{
						type: "transclude",
						attributes: {
							"$tiddler": { type: "string", value: statePrefix + chName },
							"$field": { type: "string", value: "text" }
						},
						children: [
							{ type: "element", tag: "em",
							  attributes: { "class": { type: "string", value: "appify-debug-empty" } },
							  children: [{ type: "text", text: "(empty)" }] }
						]
					}] }
				]
			});
		}
		preGridNodes.push({
			type: "element", tag: "div",
			attributes: { "class": { type: "string", value: "appify-debug-bar" } },
			children: [
				{ type: "element", tag: "span",
				  attributes: { "class": { type: "string", value: "appify-debug-title" } },
				  children: [{ type: "text", text: "Channels" }] }
			].concat(debugItems)
		});
	}

	// Build grid
	var gridStyle = "";
	if(gridAreas) gridStyle += "grid-template-areas: " + gridAreas + ";";
	if(gridColumns) gridStyle += " grid-template-columns: " + gridColumns + ";";
	if(gridRows) gridStyle += " grid-template-rows: " + gridRows + ";";

	var gridNode = {
		type: "element", tag: "div",
		attributes: {
			"class": { type: "string", value: "appify-grid appify-layout-" + layoutName },
			"style": { type: "string", value: gridStyle },
			"data-appify-app": { type: "string", value: appTitle },
			"data-appify-original-rows": { type: "string", value: originalRows }
		},
		children: slotChildren
	};

	var statewrapNode = {
		type: "statewrap",
		attributes: statewrapAttrs,
		children: bodyTree.concat(preGridNodes).concat([gridNode])
	};

	this.makeChildWidgets([statewrapNode]);
};

// --- Recursive slot builders ---

AppifyAppWidget.prototype.buildSlotContent = function(node, defaultView, editMode, appTitle, address) {
	if(node && node.direction) {
		return this.buildSplitContent(node, editMode, appTitle, address);
	}
	var view = (node && node.view !== undefined) ? node.view : defaultView;
	return this.buildLeafContent(view, editMode, appTitle, address);
};

AppifyAppWidget.prototype.buildSplitContent = function(node, editMode, appTitle, address) {
	var isH = node.direction === "horizontal";
	var ratio = node.ratio || 0.5;

	var child0 = this.buildSlotContent(node.children[0], "", editMode, appTitle, address + ".0");
	var child1 = this.buildSlotContent(node.children[1], "", editMode, appTitle, address + ".1");

	var child0HasSplit = node.children[0] && node.children[0].direction;
	var child1HasSplit = node.children[1] && node.children[1].direction;

	var pane0Class = "appify-split-pane" + (editMode && !child0HasSplit ? " appify-split-pane-edit" : "");
	var pane1Class = "appify-split-pane" + (editMode && !child1HasSplit ? " appify-split-pane-edit" : "");
	if(child0HasSplit) pane0Class += " appify-split-pane-nested";
	if(child1HasSplit) pane1Class += " appify-split-pane-nested";

	return [{
		type: "element", tag: "div",
		attributes: {
			"class": { type: "string", value: "appify-split appify-split-" + (isH ? "h" : "v") },
			"data-split-path": { type: "string", value: address },
			"data-appify-app": { type: "string", value: appTitle }
		},
		children: [
			{
				type: "element", tag: "div",
				attributes: {
					"class": { type: "string", value: pane0Class },
					"style": { type: "string", value: "flex: " + ratio + ";" }
				},
				children: child0
			},
			{
				type: "element", tag: "div",
				attributes: {
					"class": { type: "string", value: "appify-split-handle appify-split-handle-" + (isH ? "h" : "v") },
					"data-split-path": { type: "string", value: address },
					"data-appify-app": { type: "string", value: appTitle }
				}
			},
			{
				type: "element", tag: "div",
				attributes: {
					"class": { type: "string", value: pane1Class },
					"style": { type: "string", value: "flex: " + (1 - ratio) + ";" }
				},
				children: child1
			}
		]
	}];
};

AppifyAppWidget.prototype.buildLeafContent = function(viewTiddler, editMode, appTitle, address) {
	var content = [];

	if(editMode) {
		// Build label with split/delete buttons via parsed wikitext
		var isSubSlot = address.indexOf(".") !== -1;
		var viewLabel = viewTiddler ? " \u2192 " + viewTiddler : "";
		var esc = function(s) { return s.replace(/"/g, "&quot;"); };

		var wt = '<div class="appify-slot-label">' +
			'<span class="appify-slot-label-text">' + address + '<span class="appify-slot-label-tiddler">' + viewLabel + '</span></span>' +
			'<span class="appify-slot-actions">' +
			'<$button class="appify-split-btn" tooltip="Split horizontal">' +
			'<$action-appify-split app="' + esc(appTitle) + '" slot="' + esc(address) + '" operation="split-h"/>' +
			'\u2194</$button>' +
			'<$button class="appify-split-btn" tooltip="Split vertical">' +
			'<$action-appify-split app="' + esc(appTitle) + '" slot="' + esc(address) + '" operation="split-v"/>' +
			'\u2195</$button>';

		if(isSubSlot) {
			wt += '<$button class="appify-split-btn appify-split-btn-delete" tooltip="Remove this pane">' +
				'<$action-appify-split app="' + esc(appTitle) + '" slot="' + esc(address) + '" operation="delete"/>' +
				'\u2715</$button>';
		}
		wt += '</span></div>';

		var labelParsed = this.wiki.parseText("text/vnd.tiddlywiki", wt, { parseAsInline: false });
		if(labelParsed && labelParsed.tree) {
			content = content.concat(labelParsed.tree);
		}

		// Editor or view-input for empty slots
		if(viewTiddler) {
			content.push({
				type: "edit-text",
				attributes: {
					tiddler: { type: "string", value: viewTiddler },
					field: { type: "string", value: "text" },
					tag: { type: "string", value: "textarea" },
					"class": { type: "string", value: "appify-editor-textarea" },
					"default": { type: "string", value: "" }
				}
			});
		} else {
			var tempTiddler = "$:/temp/rimir/appify/view-input/" + address;
			var inputWt = '<div class="appify-view-input-container">' +
				'<$edit-text tiddler="' + esc(tempTiddler) + '" field="text" tag="input" ' +
				'placeholder="Enter tiddler title..." class="appify-view-input"/>' +
				'<$button class="appify-split-btn appify-split-btn-apply">' +
				'<$action-appify-split app="' + esc(appTitle) + '" slot="' + esc(address) + '" ' +
				'operation="set-view" value={{' + tempTiddler + '}}/>' +
				'Apply</$button></div>';
			var inputParsed = this.wiki.parseText("text/vnd.tiddlywiki", inputWt, { parseAsInline: false });
			if(inputParsed && inputParsed.tree) {
				content = content.concat(inputParsed.tree);
			}
		}
	} else {
		// View mode
		if(viewTiddler) {
			content.push({
				type: "transclude",
				attributes: { "$tiddler": { type: "string", value: viewTiddler } }
			});
		}
	}

	return content;
};

AppifyAppWidget.prototype.refresh = function(changedTiddlers) {
	if(this.appTitle && changedTiddlers[this.appTitle]) {
		this.refreshSelf();
		return true;
	}
	if(this.layoutTitle && changedTiddlers[this.layoutTitle]) {
		this.refreshSelf();
		return true;
	}
	if(changedTiddlers[EDIT_MODE_TIDDLER]) {
		this.refreshSelf();
		return true;
	}
	if(changedTiddlers[SPLITS_CHANGED_TIDDLER]) {
		this.refreshSelf();
		return true;
	}
	return this.refreshChildren(changedTiddlers);
};

exports["appify-app"] = AppifyAppWidget;

})();
","type":"application/javascript","module-type":"widget"},"$:/plugins/rimir/appify/readme":{"title":"$:/plugins/rimir/appify/readme","created":"20260317120000000","modified":"20260317120000000","type":"text/vnd.tiddlywiki","text":"! Appify

Transform TiddlyWiki into an app platform. Define full-viewport applications with named layouts, statewrap-powered state channels, and a floating launcher to switch between apps and the default wiki.

!! Features

* ''App layouts'' — predefined grid templates (sidebar+main, topbar+sidebar+main, triple-column, dashboard) with named view slots
* ''Statewrap integration'' — each app defines its own state channels and reactive rules
* ''View binding'' — each slot transcludes a tiddler that reads/writes channels by name
* ''Floating app switcher'' — always-visible FAB button to launch apps or return to the default wiki
* ''Extensible'' — register apps by tagging tiddlers with `$:/tags/rimir/appify/app`

!! Quick start

# Install the plugin (requires statewrap)
# Create an app tiddler tagged `$:/tags/rimir/appify/app` with layout and channel fields
# Create view tiddlers for each layout slot
# Click the floating button (bottom-right) to launch your app

!! App tiddler fields

|!Field |!Description |
|`appify-layout` |Layout template name (e.g., `topbar-sidebar-main`) |
|`appify-channels` |Space-separated channel names for statewrap |
|`appify-default-<name>` |Default value for channel `<name>` |
|`appify-view-<slot>` |Tiddler title to transclude into layout slot `<slot>` |
|`caption` |Display name in the app switcher |

The tiddler's text body contains `<$statewrap-rule>` definitions for reactive rules.

!! Built-in layouts

|!Name |!Slots |!Description |
|`sidebar-main` |sidebar, main |Left sidebar + main content |
|`topbar-sidebar-main` |topbar, sidebar, main |Top bar + left sidebar + main content |
|`triple-column` |left, center, right |Three equal columns |
|`dashboard` |topbar, left, right |Top bar + two equal panels |

!! Prerequisites

* TiddlyWiki 5.3.0 or later
* statewrap plugin
